// // This module decrements the 4-bit binary counter on each rising edge of the clock signal. When the reset signal is asserted, the counter will reset to its maximum value.
module top_module(
    input clk,
    input reset,
    output reg [3:0] count
);always @(posedge clk) begin
        if (reset) begin
            count <= 4'b0;
        end else begin
            count <= count + 1;
            if (count == 4'b1111) begin
                count <= 4'b0;
            end
        end
    end

endmodule
